import java.util.HashSet;
import java.util.Set;

public int subarrayBitwiseORs(int[] arr) {
    Set<Integer> result = new HashSet<>(), current, temp;
    for (int num : arr) {
        temp = new HashSet<>();
        temp.add(num);
        for (int c : current) {
            temp.add(num | c);
        }
        current = temp;
        result.addAll(current);
    }
    return result.size();
}
```

